/*
 * extraGlossary — a curated supplement of modern generative-AI / LLM terms that
 * fill gaps in the auto-generated GLOSSARY_TERMS set. Merged in GlossaryPage.jsx
 * and de-duplicated by (lowercased) term name, so anything already present in
 * the base list is ignored — no duplicates are ever shown.
 */
export const EXTRA_GLOSSARY_TERMS = [
  { term: 'Retrieval-Augmented Generation', abbr: 'RAG', category: 'AI/ML', definition: 'A technique that grounds a language model in external knowledge by retrieving relevant documents at query time and feeding them into the prompt as context, reducing hallucination and letting the model cite up-to-date or private data without retraining.', related: ['Vector Database', 'Embedding', 'Context Window', 'Hallucination'] },
  { term: 'Reinforcement Learning from Human Feedback', abbr: 'RLHF', category: 'AI/ML', definition: 'A training method that aligns a model with human preferences by collecting human rankings of model outputs, training a reward model on them, and fine-tuning the base model with reinforcement learning to maximize that reward.', related: ['Fine-Tuning', 'Reward Model', 'Alignment', 'Large Language Model'] },
  { term: 'Chain-of-Thought', abbr: 'CoT', category: 'AI/ML', definition: 'A prompting technique that asks a model to reason step by step before giving a final answer, improving performance on math, logic and multi-step tasks by making intermediate reasoning explicit.', related: ['Prompt Engineering', 'Reasoning', 'Few-Shot Learning'] },
  { term: 'Model Context Protocol', abbr: 'MCP', category: 'AI/ML', definition: 'An open standard that lets AI applications connect to external tools, data sources and services through a uniform interface, so models can read files, query databases and call APIs without bespoke integrations.', related: ['AI Agent', 'Tool Use', 'Function Calling'] },
  { term: 'AI Agent', abbr: null, category: 'AI/ML', definition: 'An autonomous system that uses a language model as a controller to plan, call tools, observe results and iterate toward a goal with minimal human intervention — going beyond single-shot text generation to take actions.', related: ['Agentic AI', 'Tool Use', 'Function Calling', 'Model Context Protocol'] },
  { term: 'Agentic AI', abbr: null, category: 'AI/ML', definition: 'A class of AI systems designed to act with autonomy — decomposing tasks, making decisions, using tools and adapting over multiple steps — rather than producing a single response to a single prompt.', related: ['AI Agent', 'Tool Use', 'Reasoning'] },
  { term: 'Tool Use', abbr: null, category: 'AI/ML', definition: "A model capability where the LLM decides to invoke external functions or APIs (search, code execution, database queries) and incorporates the results into its response, extending it beyond its training data.", related: ['Function Calling', 'AI Agent', 'Model Context Protocol'] },
  { term: 'Function Calling', abbr: null, category: 'AI/ML', definition: 'A feature that lets a language model output a structured request to call a developer-defined function with typed arguments, enabling reliable integration between natural-language prompts and real software actions.', related: ['Tool Use', 'AI Agent', 'Structured Output'] },
  { term: 'Temperature', abbr: null, category: 'AI/ML', definition: 'A sampling parameter that controls randomness in a language model’s output: low values make responses focused and deterministic, high values make them more diverse and creative.', related: ['Top-p Sampling', 'Inference', 'Large Language Model'] },
  { term: 'Top-p Sampling', abbr: 'Nucleus Sampling', category: 'AI/ML', definition: 'A decoding strategy that samples the next token from the smallest set of candidates whose cumulative probability exceeds a threshold p, balancing coherence and diversity better than fixed top-k sampling.', related: ['Temperature', 'Inference', 'Tokenization'] },
  { term: 'Knowledge Distillation', abbr: 'Distillation', category: 'AI/ML', definition: 'A compression technique where a smaller "student" model is trained to reproduce the outputs of a larger "teacher" model, retaining much of its quality at a fraction of the size and inference cost.', related: ['Quantization', 'Model Compression', 'Inference'] },
  { term: 'Mixture of Experts', abbr: 'MoE', category: 'AI/ML', definition: 'A model architecture that routes each input through only a few of many specialized sub-networks ("experts"), giving very large parameter counts while keeping the compute per token low.', related: ['Transformer', 'Parameter', 'Inference'] },
  { term: 'Low-Rank Adaptation', abbr: 'LoRA', category: 'AI/ML', definition: 'A parameter-efficient fine-tuning method that freezes the base model and trains small low-rank matrices injected into its layers, dramatically cutting the memory and storage cost of customizing large models.', related: ['Fine-Tuning', 'PEFT', 'Large Language Model'] },
  { term: 'Parameter-Efficient Fine-Tuning', abbr: 'PEFT', category: 'AI/ML', definition: 'A family of techniques (LoRA, adapters, prefix tuning) that adapt a large pretrained model to a new task by training only a small fraction of its parameters, instead of the whole network.', related: ['Low-Rank Adaptation', 'Fine-Tuning'] },
  { term: 'Prompt Injection', abbr: null, category: 'Security & SIEM', definition: 'An attack where malicious instructions hidden in user input or retrieved content trick a language model into ignoring its original instructions, leaking data or taking unintended actions.', related: ['Jailbreak', 'Guardrails', 'Retrieval-Augmented Generation'] },
  { term: 'Jailbreak', abbr: null, category: 'Security & SIEM', definition: 'A crafted prompt designed to bypass a model’s safety guardrails and elicit content or behavior the model was trained to refuse.', related: ['Prompt Injection', 'Guardrails', 'Alignment'] },
  { term: 'Guardrails', abbr: null, category: 'AI/ML', definition: 'Programmatic safety layers around an LLM that filter, validate or constrain its inputs and outputs — blocking unsafe content, enforcing formats and keeping the model on-task.', related: ['Alignment', 'Prompt Injection', 'Hallucination'] },
  { term: 'Alignment', abbr: null, category: 'AI/ML', definition: 'The research area and practice of making AI systems pursue intended human goals and values, behaving helpfully and harmlessly even as their capabilities grow.', related: ['RLHF', 'Guardrails', 'AI Safety'] },
  { term: 'AI Safety', abbr: null, category: 'AI/ML', definition: 'The field concerned with preventing harm from AI systems — covering robustness, alignment, interpretability and the avoidance of unintended or dangerous behavior.', related: ['Alignment', 'Guardrails', 'Red Teaming'] },
  { term: 'Red Teaming', abbr: null, category: 'Security & SIEM', definition: 'Adversarial testing in which experts deliberately probe an AI system for failures, unsafe outputs and exploitable weaknesses before deployment.', related: ['AI Safety', 'Jailbreak', 'Guardrails'] },
  { term: 'Reward Model', abbr: null, category: 'AI/ML', definition: 'A model trained on human preference data to score how good a candidate output is; used as the optimization signal in RLHF to fine-tune a base model toward preferred behavior.', related: ['RLHF', 'Fine-Tuning', 'Alignment'] },
  { term: 'Reasoning Model', abbr: null, category: 'AI/ML', definition: 'A language model trained or prompted to spend extra inference-time compute working through a problem step by step before answering, trading latency for accuracy on hard tasks.', related: ['Chain-of-Thought', 'Inference', 'Test-Time Compute'] },
  { term: 'Test-Time Compute', abbr: null, category: 'AI/ML', definition: 'The strategy of improving model answers by allocating more computation at inference (longer reasoning chains, sampling and selection) rather than by making the model larger.', related: ['Reasoning Model', 'Chain-of-Thought', 'Inference'] },
  { term: 'Context Window', abbr: null, category: 'AI/ML', definition: 'The maximum number of tokens a language model can attend to at once — its working memory for a request, spanning the prompt plus the generated response.', related: ['Tokenization', 'Large Language Model', 'Retrieval-Augmented Generation'] },
  { term: 'Token', abbr: null, category: 'AI/ML', definition: 'The atomic unit a language model reads and generates — typically a word piece or sub-word — produced by a tokenizer. Model cost and context limits are measured in tokens.', related: ['Tokenization', 'Context Window', 'Embedding'] },
  { term: 'Embedding', abbr: null, category: 'AI/ML', definition: 'A dense numerical vector that represents the meaning of text, images or other data so that semantically similar items sit close together in vector space — the backbone of search and RAG.', related: ['Vector Database', 'Semantic Search', 'Retrieval-Augmented Generation'] },
  { term: 'Semantic Search', abbr: null, category: 'AI/ML', definition: 'Search that matches by meaning rather than keywords, by comparing the embedding of a query against the embeddings of indexed content and ranking by vector similarity.', related: ['Embedding', 'Vector Database', 'Retrieval-Augmented Generation'] },
  { term: 'Hallucination', abbr: null, category: 'AI/ML', definition: 'When a generative model produces confident but false or fabricated information that is not grounded in its inputs or training data.', related: ['Retrieval-Augmented Generation', 'Guardrails', 'Grounding'] },
  { term: 'Grounding', abbr: null, category: 'AI/ML', definition: 'Connecting a model’s responses to verifiable external sources or real data so its claims can be traced and trusted, rather than invented.', related: ['Retrieval-Augmented Generation', 'Hallucination', 'Citation'] },
  { term: 'Foundation Model', abbr: null, category: 'AI/ML', definition: 'A large model pretrained on broad data at scale that can be adapted (via prompting or fine-tuning) to many downstream tasks — e.g. GPT, Gemini, Claude, Llama.', related: ['Large Language Model', 'Fine-Tuning', 'Pretraining'] },
  { term: 'Large Language Model', abbr: 'LLM', category: 'AI/ML', definition: 'A foundation model with billions of parameters trained on vast text corpora to predict the next token, capable of generating and understanding human language across tasks.', related: ['Foundation Model', 'Transformer', 'Token'] },
  { term: 'Small Language Model', abbr: 'SLM', category: 'AI/ML', definition: 'A compact language model (often a few billion parameters or fewer) designed to run efficiently on edge devices or at low cost, trading some capability for speed and privacy.', related: ['Large Language Model', 'Knowledge Distillation', 'Quantization'] },
  { term: 'Multimodal Model', abbr: null, category: 'AI/ML', definition: 'A model that processes and relates more than one type of data — such as text, images, audio and video — within a single system.', related: ['Foundation Model', 'Vision-Language Model', 'Embedding'] },
  { term: 'Vision-Language Model', abbr: 'VLM', category: 'AI/ML', definition: 'A multimodal model that jointly understands images and text, enabling captioning, visual question answering and image-grounded reasoning.', related: ['Multimodal Model', 'Foundation Model'] },
  { term: 'Diffusion Model', abbr: null, category: 'AI/ML', definition: 'A generative model that creates images, audio or video by learning to reverse a gradual noising process, denoising random input into coherent output — the basis of modern image generators.', related: ['Generative AI', 'Latent Space'] },
  { term: 'Generative AI', abbr: 'GenAI', category: 'AI/ML', definition: 'AI systems that produce new content — text, images, code, audio or video — rather than only classifying or predicting from existing data.', related: ['Foundation Model', 'Diffusion Model', 'Large Language Model'] },
  { term: 'Pretraining', abbr: null, category: 'AI/ML', definition: 'The initial, compute-intensive phase where a model learns general patterns from massive unlabeled data, before any task-specific fine-tuning.', related: ['Fine-Tuning', 'Foundation Model', 'Self-Supervised Learning'] },
  { term: 'Inference', abbr: null, category: 'AI/ML', definition: 'Running a trained model to produce outputs on new inputs. Inference cost, latency and throughput dominate the economics of deployed AI.', related: ['Quantization', 'Latency', 'Throughput'] },
  { term: 'Quantization', abbr: null, category: 'AI/ML', definition: 'Reducing the numerical precision of a model’s weights (e.g. from 16-bit to 4-bit) to shrink memory use and speed up inference, with minimal accuracy loss.', related: ['Knowledge Distillation', 'Inference', 'Small Language Model'] },
  { term: 'Prompt Engineering', abbr: null, category: 'AI/ML', definition: 'The practice of crafting and structuring inputs to a model to reliably get the desired output — including instructions, examples, formatting and reasoning cues.', related: ['Chain-of-Thought', 'Few-Shot Learning', 'System Prompt'] },
  { term: 'System Prompt', abbr: null, category: 'AI/ML', definition: 'A hidden, high-priority instruction that sets a model’s role, behavior and constraints for an entire conversation, distinct from per-message user prompts.', related: ['Prompt Engineering', 'Guardrails'] },
  { term: 'Few-Shot Learning', abbr: null, category: 'AI/ML', definition: 'Guiding a model to a task by including a handful of worked examples in the prompt, without any weight updates.', related: ['Zero-Shot Learning', 'Prompt Engineering', 'In-Context Learning'] },
  { term: 'Zero-Shot Learning', abbr: null, category: 'AI/ML', definition: 'Asking a model to perform a task it was never explicitly trained or shown examples for, relying solely on its pretrained general knowledge.', related: ['Few-Shot Learning', 'Prompt Engineering'] },
  { term: 'In-Context Learning', abbr: 'ICL', category: 'AI/ML', definition: 'A model’s ability to learn a task on the fly from examples and instructions placed in its prompt, without changing its weights.', related: ['Few-Shot Learning', 'Context Window', 'Prompt Engineering'] },
  { term: 'Vector Database', abbr: null, category: 'Databases', definition: 'A database optimized for storing and querying high-dimensional embedding vectors by similarity, powering semantic search and retrieval-augmented generation at scale.', related: ['Embedding', 'Semantic Search', 'Retrieval-Augmented Generation'] },
  { term: 'LLMOps', abbr: null, category: 'AIOps', definition: 'The practices and tooling for deploying, monitoring, evaluating and governing large language model applications in production — covering prompts, costs, latency, quality and safety.', related: ['MLOps', 'Observability', 'Evaluation'] },
  { term: 'AI Evaluation', abbr: 'Evals', category: 'AI/ML', definition: 'Systematic measurement of model quality against benchmarks, test sets or human/LLM judges, used to compare models and catch regressions before shipping.', related: ['LLMOps', 'Benchmark', 'LLM-as-a-Judge'] },
  { term: 'LLM-as-a-Judge', abbr: null, category: 'AI/ML', definition: 'Using a capable language model to score or compare other models’ outputs against criteria, a scalable (if imperfect) alternative to human evaluation.', related: ['AI Evaluation', 'Reward Model'] },
  { term: 'Structured Output', abbr: null, category: 'AI/ML', definition: 'Constraining a model to emit machine-readable formats such as JSON conforming to a schema, so its responses can be parsed and acted on reliably by software.', related: ['Function Calling', 'Tool Use'] },
  { term: 'Latent Space', abbr: null, category: 'AI/ML', definition: 'The compressed, abstract representation space a model learns, where each point encodes meaningful features and nearby points correspond to similar inputs.', related: ['Embedding', 'Diffusion Model'] },
];
